// Decodificar e transformar dados
const input = $input.first().json;
let data;

try {
  data = input.data?.source?.itens;
  if (!data || !Array.isArray(data)) {
    throw new Error('Dados inválidos: esperado array em data.source.itens');
  }
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'service_nf_report',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados inválidos', details: error.message }
  };
}

// Transformar e validar cada item
const transformed = data.map(item => {
  // Função para formatar datas do timestamp
  const formatDate = (timestamp) => {
    if (!timestamp) return null;
    try {
      const date = new Date(parseInt(timestamp) * 1000);
      return date.toISOString().split('T')[0] + ' ' + date.toTimeString().split(' ')[0];
    } catch {
      return null;
    }
  };

  // Função para limpar valores monetários
  const parseDecimal = (value) => {
    if (!value) return '0.00';
    let str = value.toString();
    if (str.includes(',') && str.includes('.')) {
      str = str.replace(/\./g, '').replace(',', '.');
    } else if (str.includes(',')) {
      str = str.replace(',', '.');
    }
    return parseFloat(str).toFixed(2);
  };

  return {
    ID: item.ID || '',
    RPS: item.RPS || '',
    Nota: item.Nota || '',
    Cliente: item.Cliente || '',
    CNPJ: item.CNPJ || '',
    Endereco: item.Endereco || '',
    Numero: item.Numero || '',
    Complemento: item.Complemento || '',
    Bairro: item.Bairro || '',
    Cidade: item.Cidade || '',
    Estado: item.Estado || '',
    CEP: item.CEP || '',
    Email: item.Email || '',
    Telefone: item.Telefone || '',
    Vendedor: item.Vendedor || '',
    ValorServicos: parseDecimal(item.ValorServicos),
    ValorTotal: parseDecimal(item.ValorTotal),
    TotalParcelas: item.TotalParcelas || '',
    ValorDeducoes: parseDecimal(item.ValorDeducoes),
    Aliquota: item.Aliquota || '',
    ValorISS: parseDecimal(item.ValorISS),
    ISSRetido: item.ISSRetido || '',
    ValorCOFINS: parseDecimal(item.ValorCOFINS),
    ValorPIS: parseDecimal(item.ValorPIS),
    ValorCSLL: parseDecimal(item.ValorCSLL),
    ValorIR: parseDecimal(item.ValorIR),
    ValorINSS: parseDecimal(item.ValorINSS),
    ValorTributos: parseDecimal(item.ValorTributos),
    DataPedido: formatDate(item.DataPedido),
    LocalPrestacao: item.LocalPrestacao || '',
    Contas: item.Contas || '',
    Chave: item.Chave || '',
    Protocolo: item.Protocolo || '',
    Descricao: item.Descricao || '',
    DataEmissao: formatDate(item.DataEmissao),
    Situacao: item.Situacao || '',
    DataCad: formatDate(item.DataCad),
    DataMod: formatDate(item.DataMod),
    ObservacoesInternas: item.ObservacoesInternas || '',
    cc_ref: '-1'
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'data_transform_success',
  count: transformed.length,
  level: 'info'
}));

return { transformed };

// Enriquecer dados com centro de custos
const transformedData = $input.first().json.transformed;
const enrichmentData = $input.last().json;

// Criar mapa de enriquecimento
const enrichmentMap = {};
enrichmentData.forEach(row => {
  enrichmentMap[row.numeronfs] = {
    cc_ref: row.cc_ref || '-1',
    obs_interno_pedido: row.obs_interno_pedido || ''
  };
});

// Enriquecer dados transformados
const enrichedData = transformedData.map(item => {
  const enrichment = enrichmentMap[item.RPS];

  if (enrichment) {
    item.cc_ref = enrichment.cc_ref;
    if (!item.ObservacoesInternas) {
      item.ObservacoesInternas = enrichment.obs_interno_pedido;
    }
  } else {
    // Fallback: extrair CC das observações
    if (item.ObservacoesInternas) {
      const ccMatch = item.ObservacoesInternas.match(/CC[:\s]*([A-Z0-9]+)/i);
      if (ccMatch) {
        item.cc_ref = ccMatch[1];
      }
    }
  }

  return item;
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'enrichment_success',
  enriched_count: enrichedData.filter(item => item.cc_ref !== '-1').length,
  total_count: enrichedData.length,
  level: 'info'
}));

return { enriched: enrichedData };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { ok: true, message: 'Service NF report processed successfully' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process service NF report' }
};
